def clasificar_tipo(serie):
    nombre = serie.name.lower()
    if is_bool_dtype(serie):
        return 'Booleana'
    if is_datetime64_any_dtype(serie) or 'date' in nombre or 'time' in nombre:
        return 'Fecha'
    if is_numeric_dtype(serie):
        return 'Numérica'
    if is_object_dtype(serie):
        longitud_promedio = serie.dropna().astype(str).str.len().mean()
        if longitud_promedio and longitud_promedio > 30:
            return 'Texto'
        return 'Categórica'
    return 'Categórica'

